import { MakeLogicType, actions, connect, kea, path, reducers, selectors } from 'kea'

import { mcpHintLogic } from 'lib/components/MCPHint/mcpHintLogic'
import { preflightLogic } from 'lib/logic/preflightLogic'
// eslint-disable-next-line import/no-cycle
import { userLogic } from 'scenes/userLogic'
import type { PreflightStatus, UserType } from '../../../types'


export type FakeStatusOverride = 'none' | 'operational' | 'degraded_performance' | 'partial_outage' | 'major_outage'
export type FakeBillingAlert = 'none' | 'info' | 'warning' | 'error'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface superpowersLogicValues {
    dismissedSurfaces: Record<string, true>; // mcpHintLogic
    effectiveOptOut: boolean; // mcpHintLogic
    preflight: PreflightStatus | null; // preflightLogic
    user: UserType | null; // userLogic
    fakeBillingAlert: FakeBillingAlert;
    fakeStatusOverride: FakeStatusOverride;
    isSuperpowersOpen: boolean;
    mcpHintsDismissed: boolean;
    superpowersEnabled: boolean | undefined;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface superpowersLogicActions {
    reenableMCPHints: () => {
        value: true;
    }; // mcpHintLogic
    closeSuperpowers: () => {
        value: true;
    };
    openSuperpowers: () => {
        value: true;
    };
    setFakeBillingAlert: (alert: FakeBillingAlert) => {
        alert: FakeBillingAlert;
    };
    setFakeStatusOverride: (status: FakeStatusOverride) => {
        status: FakeStatusOverride;
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface superpowersLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        superpowersEnabled: (user: UserType | null, preflight: PreflightStatus | null) => boolean | undefined;
        mcpHintsDismissed: (dismissedSurfaces: Record<string, true>, effectiveOptOut: boolean) => boolean;
    };
}

export type superpowersLogicType = MakeLogicType<superpowersLogicValues, superpowersLogicActions, Record<string, any>, superpowersLogicMeta>;

export const superpowersLogic = kea<superpowersLogicType>([
    path(['lib', 'components', 'Superpowers', 'superpowersLogic']),
    connect(() => ({
        values: [
            userLogic,
            ['user'],
            preflightLogic,
            ['preflight'],
            mcpHintLogic,
            ['dismissedSurfaces', 'effectiveOptOut'],
        ],
        actions: [mcpHintLogic, ['reenable as reenableMCPHints']],
    })),
    actions({
        openSuperpowers: true,
        closeSuperpowers: true,
        setFakeStatusOverride: (status: FakeStatusOverride) => ({ status }),
        setFakeBillingAlert: (alert: FakeBillingAlert) => ({ alert }),
    }),
    reducers({
        isSuperpowersOpen: [
            false,
            {
                openSuperpowers: () => true,
                closeSuperpowers: () => false,
            },
        ],
        fakeStatusOverride: [
            'none' as FakeStatusOverride,
            {
                setFakeStatusOverride: (_, { status }) => status,
            },
        ],
        fakeBillingAlert: [
            'none' as FakeBillingAlert,
            {
                setFakeBillingAlert: (_, { alert }) => alert,
            },
        ],
    }),
    selectors({
        superpowersEnabled: [
            (s) => [s.user, s.preflight],
            (user: UserType | null, preflight: PreflightStatus | null) => {
                return user?.is_staff || preflight?.is_debug || preflight?.instance_preferences?.debug_queries
            },
        ],
        mcpHintsDismissed: [
            (s) => [s.dismissedSurfaces, s.effectiveOptOut],
            (dismissedSurfaces: Record<string, true>, effectiveOptOut: boolean): boolean =>
                effectiveOptOut || Object.keys(dismissedSurfaces).length > 0,
        ],
    }),
])
